}

for task, (start, end) in tasks.items():
    for n in range(start, end+1):
        path = f'public/questions/toefl/listening/{task}/{n:03d}.json'
        try:
            with open(path) as f:
                data = json.load(f)
            if task == 'response':
                assert len(data['questions']) == 8, f'{path}: expected 8 questions, got {len(data[\"questions\"])}'
